// Compute period = previous month in YYYY-MM format
const now = new Date();
const prev = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const year = prev.getFullYear();
const month = String(prev.getMonth() + 1).padStart(2, '0');
const period = `${year}-${month}`;
return [{ json: { period, year, month } }];

// Parse the 'Entries: N' and 'Partner total: $X,XXX.XX' lines from stdout.
const out = $input.first().json.stdout || '';
const period = $('Compute Period (prev month)').first().json.period;
const year = $('Compute Period (prev month)').first().json.year;

const entriesMatch = out.match(/Entries:\s+(\d+)/);
const totalMatch = out.match(/Partner total:\s+\$([0-9,\.]+)/);
const persistedMatch = out.match(/PERSISTED/);

return [{
  json: {
    period,
    year,
    entry_count: entriesMatch ? parseInt(entriesMatch[1], 10) : 0,
    partner_total_usd: totalMatch ? totalMatch[1] : '0.00',
    persisted: !!persistedMatch,
    ledger_csv_path: `/opt/pacer/reports/payouts/${period}/ledger_${period}.csv`,
    nec_csv_path: `/opt/pacer/reports/payouts/${period}/1099nec_${year}.csv`,
    raw_stdout: out,
  }
}];

